import axios from 'axios';

// OpenAI API Configuration
const OPENAI_API_KEY = process.env.REACT_APP_OPENAI_API_KEY || 'your-openai-api-key-here';
const OPENAI_API_URL = 'https://api.openai.com/v1/chat/completions';

// Create axios instance with default configuration
const openaiApi = axios.create({
  baseURL: OPENAI_API_URL,
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${OPENAI_API_KEY}`
  },
  timeout: 30000 // 30 seconds timeout
});

/**
 * Send message to OpenAI API
 * @param {string} message - User message to send
 * @param {Array} conversationHistory - Previous messages for context
 * @returns {Promise<string>} - AI response text
 */
export const sendMessageToAI = async (message, conversationHistory = []) => {
  try {
    // Prepare messages array with conversation history
    const messages = [
      ...conversationHistory,
      { role: 'user', content: message }
    ];

    // Make API request
    const response = await openaiApi.post('', {
      model: 'gpt-3.5-turbo',
      messages: messages,
      max_tokens: 150,
      temperature: 0.7,
      top_p: 1,
      frequency_penalty: 0,
      presence_penalty: 0
    });

    // Extract and return the AI response
    const aiResponse = response.data.choices[0]?.message?.content;

    if (!aiResponse) {
      throw new Error('No response received from OpenAI');
    }

    return aiResponse.trim();

  } catch (error) {
    console.error('OpenAI API Error:', error);

    // Handle different types of errors
    if (error.response) {
      // API responded with error status
      const { status, data } = error.response;

      switch (status) {
        case 401:
          throw new Error('Invalid API key. Please check your OpenAI API key.');
        case 429:
          throw new Error('Rate limit exceeded. Please try again later.');
        case 500:
          throw new Error('OpenAI server error. Please try again later.');
        default:
          throw new Error(`API Error: ${data?.error?.message || 'Unknown error occurred'}`);
      }
    } else if (error.request) {
      // Network error
      throw new Error('Network error. Please check your internet connection.');
    } else {
      // Other error
      throw new Error(`Error: ${error.message}`);
    }
  }
};

/**
 * Stream message to OpenAI API (for real-time responses)
 * @param {string} message - User message to send
 * @param {Array} conversationHistory - Previous messages for context
 * @param {Function} onChunk - Callback for each chunk of response
 * @returns {Promise<void>}
 */
export const streamMessageToAI = async (message, conversationHistory = [], onChunk) => {
  try {
    const messages = [
      ...conversationHistory,
      { role: 'user', content: message }
    ];

    const response = await fetch(OPENAI_API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${OPENAI_API_KEY}`
      },
      body: JSON.stringify({
        model: 'gpt-3.5-turbo',
        messages: messages,
        max_tokens: 150,
        temperature: 0.7,
        stream: true
      })
    });

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    const reader = response.body.getReader();
    const decoder = new TextDecoder();

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      const chunk = decoder.decode(value);
      const lines = chunk.split('\n');

      for (const line of lines) {
        if (line.startsWith('data: ')) {
          const data = line.slice(6);
          if (data === '[DONE]') continue;

          try {
            const parsed = JSON.parse(data);
            const content = parsed.choices[0]?.delta?.content;
            if (content) {
              onChunk(content);
            }
          } catch (e) {
            // Ignore parsing errors for SSE chunks
          }
        }
      }
    }

  } catch (error) {
    console.error('OpenAI Streaming Error:', error);
    throw new Error(`Streaming error: ${error.message}`);
  }
};

/**
 * Validate API key
 * @returns {boolean} - True if API key is valid format
 */
export const validateApiKey = () => {
  const apiKey = process.env.REACT_APP_OPENAI_API_KEY;
  return apiKey && apiKey.startsWith('sk-') && apiKey.length > 20;
};

export default {
  sendMessageToAI,
  streamMessageToAI,
  validateApiKey
};
